const raw = $json.body ?? $json;

function text(value, fallback = '') {
  if (value === null || value === undefined) return fallback;
  return String(value).trim();
}

function boolean(value, fallback = false) {
  if (value === true || value === false) return value;
  const normalized = text(value).toLowerCase();
  if (['1', 'true', 'sim', 'yes', 'on'].includes(normalized)) return true;
  if (['0', 'false', 'nao', 'não', 'no', 'off'].includes(normalized)) return false;
  return fallback;
}

function modality(value) {
  const normalized = text(value).toLowerCase();
  if (['online', 'on-line', 'remoto'].includes(normalized)) return 'online';
  if (['presencial', 'in_person', 'in-person'].includes(normalized)) return 'presencial';
  return '';
}

const action = text(raw.action, 'search').toLowerCase();
if (!['search', 'hold', 'confirm', 'release'].includes(action)) {
  throw new Error('action deve ser search, hold, confirm ou release.');
}

const date = text(raw.date || raw.preferred_date || raw.data);
const utcOffset = text(raw.utc_offset, '-03:00');
const workStart = text(raw.work_start || raw.start_time, '00:00');
const workEnd = text(raw.work_end || raw.end_time, '23:59');

if (action === 'search' && !/^\d{4}-\d{2}-\d{2}$/.test(date)) {
  throw new Error('Para search, informe date no formato YYYY-MM-DD.');
}

const eventId = text(raw.google_event_id || raw.event_id);
if (action !== 'search' && !eventId) {
  throw new Error('Para hold, confirm ou release, informe google_event_id.');
}

const calendarId = text(raw.calendar_id, 'primary');
const encodedCalendar = encodeURIComponent(calendarId);
const windowStartIso = action === 'search' ? `${date}T${workStart}:00${utcOffset}` : '';
const windowEndIso = action === 'search' ? `${date}T${workEnd}:59${utcOffset}` : '';
const googleListUrl = action === 'search'
  ? `https://www.googleapis.com/calendar/v3/calendars/${encodedCalendar}/events?singleEvents=true&orderBy=startTime&showDeleted=false&maxResults=2500&timeMin=${encodeURIComponent(windowStartIso)}&timeMax=${encodeURIComponent(windowEndIso)}`
  : '';
const googleEventUrl = eventId
  ? `https://www.googleapis.com/calendar/v3/calendars/${encodedCalendar}/events/${encodeURIComponent(eventId)}`
  : '';

return [{
  json: {
    action,
    is_search: action === 'search',
    tenant_id: Number(raw.tenant_id || 0),
    request_id: text(raw.request_id || raw.availability_request_id, `req-${Date.now()}`),
    appointment_id: raw.appointment_id ? Number(raw.appointment_id) : null,
    conversation_id: raw.conversation_id ? Number(raw.conversation_id) : null,
    contact_id: raw.contact_id ? Number(raw.contact_id) : null,
    date,
    work_start: workStart,
    work_end: workEnd,
    window_start_iso: windowStartIso,
    window_end_iso: windowEndIso,
    calendar_id: calendarId,
    google_event_id: eventId,
    google_list_url: googleListUrl,
    google_event_url: googleEventUrl,
    modality: modality(raw.modality || raw.format || raw.formato),
    customer_name: text(raw.customer_name || raw.contact_name || raw.nome, 'Cliente'),
    customer_phone: text(raw.customer_phone || raw.phone || raw.telefone),
    online_title: text(raw.online_title, 'VAGO — ONLINE'),
    in_person_title: text(raw.in_person_title, 'VAGO — PRESENCIAL'),
    hold_prefix: text(raw.hold_prefix, 'PRÉ-RESERVADO'),
    confirmed_prefix: text(raw.confirmed_prefix, 'AGENDADO'),
    require_transparent: boolean(raw.require_transparent, true),
    timezone: text(raw.timezone, 'America/Sao_Paulo'),
    utc_offset: utcOffset,
    callback_url: text(raw.callback_url, 'https://rsconnect.rsautomacaodigital.cloud/webhooks/calendar/availability'),
    callback_token: text(raw.callback_token),
    notes: text(raw.notes || raw.summary || raw.resumo)
  }
}];

const cfg = $('Normalizar operação').first().json;
const events = Array.isArray($json.items) ? $json.items : [];

function normalizeTitle(value) {
  return String(value || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[–—-]+/g, ' - ')
    .replace(/\s+/g, ' ')
    .trim()
    .toUpperCase();
}

function inferModality(summary) {
  const normalized = normalizeTitle(summary);
  if (normalized === normalizeTitle(cfg.online_title)) return 'online';
  if (normalized === normalizeTitle(cfg.in_person_title)) return 'presencial';
  return '';
}

const allowedTitles = [normalizeTitle(cfg.online_title), normalizeTitle(cfg.in_person_title)];

const slots = events
  .filter(event => event && event.id && event.status !== 'cancelled')
  .filter(event => allowedTitles.includes(normalizeTitle(event.summary)))
  .filter(event => !cfg.require_transparent || String(event.transparency || 'opaque').toLowerCase() === 'transparent')
  .map(event => ({ event, modality: inferModality(event.summary) }))
  .filter(item => !cfg.modality || item.modality === cfg.modality)
  .map(item => ({
    start: item.event.start?.dateTime || item.event.start?.date || null,
    end: item.event.end?.dateTime || item.event.end?.date || null,
    label: item.event.start?.dateTime
      ? new Date(item.event.start.dateTime).toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit', timeZone: cfg.timezone })
      : 'Dia inteiro',
    modality: item.modality,
    google_event_id: item.event.id,
    google_calendar_id: cfg.calendar_id,
    google_summary: item.event.summary || '',
    google_transparency: item.event.transparency || 'opaque',
    source: 'google_marked_slots'
  }));

const callbackPayload = {
  event: 'calendar.availability.result',
  ok: true,
  tenant_id: cfg.tenant_id,
  request_id: cfg.request_id,
  appointment_id: cfg.appointment_id,
  conversation_id: cfg.conversation_id,
  contact_id: cfg.contact_id,
  source: 'google_marked_slots',
  date: cfg.date,
  timezone: cfg.timezone,
  slots,
  meta: {
    calendar_id: cfg.calendar_id,
    online_title: cfg.online_title,
    in_person_title: cfg.in_person_title,
    require_transparent: cfg.require_transparent,
    events_read: events.length
  }
};

return [{ json: { ...cfg, slots, callback_payload: callbackPayload } }];

const cfg = $('Normalizar operação').first().json;
const event = $json || {};

function normalizeTitle(value) {
  return String(value || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[–—-]+/g, ' - ')
    .replace(/\s+/g, ' ')
    .trim()
    .toUpperCase();
}

function inferModality(summary) {
  const normalized = normalizeTitle(summary);
  if (normalized.includes('ONLINE')) return 'online';
  if (normalized.includes('PRESENCIAL')) return 'presencial';
  return cfg.modality || '';
}

const currentSummary = String(event.summary || '');
const normalizedCurrent = normalizeTitle(currentSummary);
const normalizedOnline = normalizeTitle(cfg.online_title);
const normalizedInPerson = normalizeTitle(cfg.in_person_title);
const currentModality = cfg.modality || inferModality(currentSummary);
const modalityLabel = currentModality === 'presencial' ? 'PRESENCIAL' : 'ONLINE';

if (cfg.action === 'hold') {
  if (![normalizedOnline, normalizedInPerson].includes(normalizedCurrent)) {
    throw new Error('O evento não está mais marcado como VAGO. Atualize a disponibilidade antes de reservar.');
  }
  if (cfg.require_transparent && String(event.transparency || 'opaque').toLowerCase() !== 'transparent') {
    throw new Error('O evento VAGO não está como Disponível/transparent.');
  }
}

if (cfg.action === 'confirm' && !normalizedCurrent.startsWith(normalizeTitle(cfg.hold_prefix))) {
  throw new Error('Somente um evento pré-reservado pode ser confirmado.');
}

if (cfg.action === 'release') {
  const canRelease = normalizedCurrent.startsWith(normalizeTitle(cfg.hold_prefix))
    || normalizedCurrent.startsWith(normalizeTitle(cfg.confirmed_prefix));
  if (!canRelease) {
    throw new Error('O evento não está pré-reservado ou agendado.');
  }
}

let state;
let newSummary;
let transparency;

if (cfg.action === 'hold') {
  state = 'held';
  newSummary = `${cfg.hold_prefix} — ${modalityLabel} — ${cfg.customer_name}`;
  transparency = 'opaque';
} else if (cfg.action === 'confirm') {
  state = 'confirmed';
  newSummary = `${cfg.confirmed_prefix} — ${modalityLabel} — ${cfg.customer_name}`;
  transparency = 'opaque';
} else {
  state = 'released';
  newSummary = currentModality === 'presencial' ? cfg.in_person_title : cfg.online_title;
  transparency = 'transparent';
}

const descriptionLines = cfg.action === 'release'
  ? []
  : [
      'Origem: RS Connect',
      `Cliente: ${cfg.customer_name}`,
      cfg.customer_phone ? `Telefone: ${cfg.customer_phone}` : '',
      cfg.appointment_id ? `Pré-agendamento: #${cfg.appointment_id}` : '',
      cfg.conversation_id ? `Conversa: #${cfg.conversation_id}` : '',
      `Modalidade: ${modalityLabel}`,
      `Status: ${state}`,
      cfg.notes ? `Observações: ${cfg.notes}` : ''
    ].filter(Boolean);

const patchBody = {
  summary: newSummary,
  description: descriptionLines.join('\n'),
  transparency,
  extendedProperties: {
    private: {
      rs_connect_tenant_id: String(cfg.tenant_id || ''),
      rs_connect_request_id: String(cfg.request_id || ''),
      rs_connect_appointment_id: String(cfg.appointment_id || ''),
      rs_connect_state: state,
      rs_connect_modality: currentModality
    }
  }
};

return [{
  json: {
    ...cfg,
    original_event: event,
    original_summary: currentSummary,
    original_transparency: event.transparency || 'opaque',
    google_etag: event.etag || '',
    resolved_modality: currentModality,
    target_state: state,
    patch_body: patchBody
  }
}];
